303					t.Fatalf("%s description missing PASSWORD_CHANGE_REQUIRED: %s", route.path, operation.Description)
304				}
305				response := operation.Responses.Map()["403"]
306				if response == nil || response.Value == nil {
307					t.Fatalf("%s missing documented 403 password-change response", route.path)
308				}
309				if response.Value.Description == nil || !strings.Contains(*response.Value.Description, "Password change") {
310					description := ""
311					if response.Value.Description != nil {
312						description = *response.Value.Description
313					}
314					t.Fatalf("%s 403 response does not describe password-change gate: %s", route.path, description)
315				}
316			})
317		}
